import { Card } from "@mui/material";
import React, { useEffect, useState } from "react";
import SimpleHeader from "../../components/SimpleHeader";
import Box from "@mui/material/Box";
import CardContent from "@mui/material/CardContent";
import { Typography } from "@mui/material";
import TextField from "@mui/material/TextField";
import Button from "@mui/material/Button";
import RemoveCircleIcon from "@mui/icons-material/RemoveCircle";
import Chip from "@mui/material/Chip";
import { useNavigate } from "react-router-dom";
import CreateNormalPoll from "../../components/CreateNormalPoll";
import CreateImagePoll from "../../components/CreateImagePoll";
const CreatePoll = () => {
  const [fields, setFields] = useState([
    { value: null, description: "", image: "" },
    { value: null, description: "", image: "" },
    { value: null, description: "", image: "" },
  ]);
  const [isSelected, setIsSelected] = useState("Comment");
  const [question, setQuestion] = useState("");
  const [image, setImage] = useState("");
  let navigate = useNavigate();
  const routeChange = () => {
    let path = "/";
    navigate(path);
  };

  function handleChange(i, event) {
    const values = [...fields];
    values[i].value = event.target.value;
    values[i].description = event.target.value;
    setFields(values);
  }

  function handleChangeDescription(i, event) {
    const values = [...fields];
    values[i].description = event.target.value;
    setFields(values);
  }
  function handleChangeImage(i, event) {
    const values = [...fields];
    values[i].image = event.target.value;
    setFields(values);
  }

  function handleAdd() {
    const values = [...fields];
    values.push({ value: null, description: "", image: "" });
    setFields(values);
  }

  function handleRemove(i) {
    const values = [...fields];
    values.splice(i, 1);
    setFields(values);
  }

  return (
    <>
      <SimpleHeader headerText="Create Poll" routeChange={routeChange} />
      <Box sx={{ minWidth: 275, marginTop: 5, height: "100%" }}>
        <Card variant="outlined">
          <CardContent>
            <div style={{ marginBottom: 15 }}>
              <Typography sx={{ fontSize: 14 }}>Poll Type</Typography>
              <Chip
                label="Comment"
                style={{
                  background: isSelected == "Comment" ? "#606060" : "#E0E0E0",
                  color: isSelected == "Comment" ? "#fff" : "#606060",
                  cursor: "pointer",
                }}
                onClick={() => setIsSelected("Comment")}
              />
              <Chip
                label="Image"
                style={{
                  background: isSelected == "Image" ? "#606060" : "#E0E0E0",
                  color: isSelected == "Image" ? "#fff" : "#606060",
                  cursor: "pointer",
                  marginLeft: 5,
                }}
                onClick={() => setIsSelected("Image")}
              />
            </div>

            {isSelected == "Comment" ? (
              <CreateNormalPoll
                setQuestion={setQuestion}
                fields={fields}
                handleChange={handleChange}
                handleRemove={handleRemove}
                handleAdd={handleAdd}
                key="Comment"
              />
            ) : (
              <CreateImagePoll
                setQuestion={setQuestion}
                fields={fields}
                handleChange={handleChange}
                handleRemove={handleRemove}
                handleChangeDescription={handleChangeDescription}
                handleAdd={handleAdd}
                handleChangeImage={handleChangeImage}
                key="Image"
              />
            )}
          </CardContent>
        </Card>
      </Box>
      <div
        style={{
          display: "flex",
          justifyContent: "space-evenly",
          alignItems: "center",
          marginTop: 30,
          marginBottom: 30,
        }}
      >
        <Button variant="outlined">Cancel</Button>
        <Button variant="contained">Create Poll</Button>
      </div>
    </>
  );
};

export default CreatePoll;
