import React, { useState, useEffect } from "react";
import { Typography } from "@mui/material";
import TextField from "@mui/material/TextField";
import Button from "@mui/material/Button";
import RemoveCircleIcon from "@mui/icons-material/RemoveCircle";
import Grid from "@mui/material/Grid";
const CreateImagePoll = (props) => {
  const {
    setQuestion,
    fields,
    handleChange,
    handleRemove,
    handleAdd,
    handleChangeDescription,
    handleChangeImage,
    image,
  } = props;

  // const [selectedFile, setSelectedFile] = useState();
  // const [preview, setPreview] = useState();

  // // create a preview as a side effect, whenever selected file is changed
  // useEffect(() => {
  //   if (!selectedFile) {
  //     setPreview(undefined);
  //     return;
  //   }

  //   const objectUrl = URL.createObjectURL(selectedFile);
  //   setPreview(objectUrl);

  //   // free memory when ever this component is unmounted
  //   return () => URL.revokeObjectURL(objectUrl);
  // }, [selectedFile]);

  // const onSelectFile = (idx, e) => {
  //   if (!e.target.files || e.target.files.length === 0) {
  //     setSelectedFile(undefined);
  //     return;
  //   }

  //   // I've kept this example simple by using the first image instead of multiple
  //   setSelectedFile(e.target.files[0]);
  // };
  return (
    <>
      <Typography sx={{ fontSize: 14 }}>Create a multiple-choice Image poll</Typography>
      <TextField
        id="outlined-textarea"
        multiline
        fullWidth
        style={{ marginBottom: 15 }}
        rows={3}
        onChange={(e) => setQuestion(e.target.value)}
      />
      <Typography sx={{ fontSize: 14 }}>Poll Choices</Typography>
      <Grid container spacing={2}>
        {fields.map((field, idx) => {
          return (
            <Grid item xs={6} md={6} key={`${field}-${idx}`}>
              <div key={`${field}-${idx}`} style={{ position: "relative" }}>
                <input type="file" accept="image/*" onChange={(e) => handleChangeImage(idx, e)} />
                <TextField
                  variant="outlined"
                  label={"Poll Choice " + (idx + 1)}
                  fullWidth
                  name="Poll"
                  key={`${field}-${idx}`}
                  onChange={(e) => handleChange(idx, e)}
                />
                <TextField
                  variant="outlined"
                  label={"Description"}
                  fullWidth
                  key={`Description  ${field}-${idx}`}
                  name="Description"
                  style={{ marginBottom: 5 }}
                  onChange={(e) => handleChangeDescription(idx, e)}
                />
                <RemoveCircleIcon
                  onClick={() => handleRemove(idx)}
                  style={{
                    position: "absolute",
                    cursor: "pointer",
                    top: "-10px",
                    right: "-10px",
                  }}
                />
              </div>
            </Grid>
          );
        })}
      </Grid>
      <Button variant="outlined" onClick={() => handleAdd()}>
        + Add Another Choice
      </Button>
    </>
  );
};

export default CreateImagePoll;
