import React from "react";
import { Typography } from "@mui/material";
import TextField from "@mui/material/TextField";
import Button from "@mui/material/Button";
import RemoveCircleIcon from "@mui/icons-material/RemoveCircle";
const CreateNormalPoll = (props) => {
  const { setQuestion, fields, handleChange, handleRemove, handleAdd } = props;
  return (
    <>
      <Typography sx={{ fontSize: 14 }}>Create a multiple-choice poll</Typography>
      <TextField
        id="outlined-textarea"
        multiline
        fullWidth
        style={{ marginBottom: 15 }}
        rows={3}
        onChange={(e) => setQuestion(e.target.value)}
      />
      <Typography sx={{ fontSize: 14 }}>Poll Choices</Typography>
      {fields.map((field, idx) => {
        return (
          <div key={`${field}-${idx}`} style={{ display: "flex", alignItems: "center" }}>
            <TextField
              variant="outlined"
              label={"Poll Choice " + (idx + 1)}
              fullWidth
              key={`${field}-${idx}`}
              style={{ marginBottom: 5 }}
              onChange={(e) => handleChange(idx, e)}
            />
            <RemoveCircleIcon onClick={() => handleRemove(idx)} />
          </div>
        );
      })}
      <Button variant="outlined" onClick={() => handleAdd()}>
        + Add Another Choice
      </Button>
    </>
  );
};

export default CreateNormalPoll;
